import{_ as t,o,c as a,a2 as i}from"./chunks/framework.CKCxdkvf.js";const g=JSON.parse('{"title":"RFC-011 — Science page · render pipeline & content authoring","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-011.md","filePath":"rfc/RFC-011.md"}'),r={name:"rfc/RFC-011.md"};function n(s,e,d,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="rfc-011-—-science-page-·-render-pipeline-content-authoring" tabindex="-1">RFC-011 — Science page · render pipeline &amp; content authoring <a class="header-anchor" href="#rfc-011-—-science-page-·-render-pipeline-content-authoring" aria-label="Permalink to &quot;RFC-011 — Science page · render pipeline &amp; content authoring&quot;">​</a></h1><p><em>Orrery · Open RFC · v0.1 · May 2026</em></p><blockquote><p><strong>Status:</strong> Open <strong>Author:</strong> product <strong>Closes into:</strong> ADR-034 (math renderer), ADR-035 (diagram pipeline), ADR-036 (cross-screen <code>?</code>-chip pattern) <strong>Slice gate:</strong> v0.4 <strong>Why this is an RFC:</strong> PRD-008 locks the <em>what</em> (in-app encyclopedia, six tabs, ~40 sections, ?-chip cross-link from existing screens). It does not lock the <em>how</em> — math rendering, diagram authoring, and the cross-screen UX of the <code>?</code> chip each have multiple defensible answers with real trade-offs. Each open question below has two-to-four options; we ship the resolution as ADRs alongside the implementation.</p></blockquote><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The simulator already references ~90 distinct scientific concepts across docs and code (full inventory in PRD-008 §appendix). The user-visible terminology surfaces today are:</p><ul><li><code>/plan</code> porkchop axes + colour bar</li><li><code>/fly</code> HUD (∆v · MET · v∞ · velocity · distance)</li><li><code>/missions</code> FLIGHT tab (C3 · v∞ · TLI · TMI · TCM · EDL · ∆v totals)</li><li><code>/explore</code> planet panels (Keplerian elements · semi-major axis · eccentricity · orbital period)</li><li><code>/earth</code> orbit-altitude regimes (LEO · MEO · GEO · L2)</li><li><code>/moon</code> (and the new <code>/mars</code> per PRD-009) — landing-site narratives that mention free-return, direct-ascent, gravity assist</li></ul><p>Today every one of these terms is undefined in-app. The reader either knows the term or must leave the app to look it up. PRD-008 closes that gap with <code>/science</code>.</p><p>Three implementation questions are independent of <em>content</em> and worth resolving up front: math rendering, diagram authoring, and the cross-screen <code>?</code>-chip wiring.</p><hr><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><h3 id="oq-1-—-how-do-we-render-math-in-section-bodies" tabindex="-1">OQ-1 — How do we render math in section bodies? <a class="header-anchor" href="#oq-1-—-how-do-we-render-math-in-section-bodies" aria-label="Permalink to &quot;OQ-1 — How do we render math in section bodies?&quot;">​</a></h3><p>The app references formulas like <code>v = √(μ·(2/r − 1/a))</code> (vis-viva), <code>Δv = Isp·g·ln(m₀/m_f)</code> (Tsiolkovsky), <code>r = a·(1 − e²)/(1 + e·cos ν)</code> (Kepler conic). They must render cleanly in dark theme, scale on mobile, and not blow up the JS payload.</p><table tabindex="0"><thead><tr><th>Option</th><th>Bundle</th><th>Render path</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>A. KaTeX (server-rendered at build)</strong></td><td>~70 KB minified gzipped CSS, <strong>0 KB JS at runtime</strong> (HTML output baked in at prerender)</td><td>Compile-time</td><td>Fast, no client lib, simple authoring (LaTeX source in JSON)</td><td>KaTeX rendering only at build; no client-side math edits possible (we don&#39;t need them anyway)</td></tr><tr><td><strong>B. KaTeX (client-side)</strong></td><td>~70 KB JS + CSS</td><td>Runtime</td><td>Same renderer; trivial drop-in if we ever need dynamic math</td><td>Adds 70 KB to client bundle; payload regression for a feature ≤80% of users will reach</td></tr><tr><td><strong>C. MathJax v3</strong></td><td>~250 KB+</td><td>Runtime</td><td>Most complete LaTeX support; handles edge cases KaTeX can&#39;t</td><td>3.5× larger than KaTeX; we don&#39;t need the edge cases</td></tr><tr><td><strong>D. Hand-rolled SVG per formula</strong></td><td>~0 (SVG inlined)</td><td>Compile-time</td><td>Bullet-proof; pixel-perfect</td><td>Authoring nightmare; one-off per formula; brittle when the formula changes</td></tr></tbody></table><p><strong>Recommendation: A — KaTeX server-rendered at build.</strong> SvelteKit&#39;s prerender step compiles each section&#39;s <code>formula_latex</code> field into HTML once; the client never loads KaTeX. We get LaTeX authoring ergonomics without any runtime cost. Any edge case KaTeX can&#39;t handle becomes an inline SVG (option D) for that one formula.</p><hr><h3 id="oq-2-—-how-do-we-author-the-diagrams" tabindex="-1">OQ-2 — How do we author the diagrams? <a class="header-anchor" href="#oq-2-—-how-do-we-author-the-diagrams" aria-label="Permalink to &quot;OQ-2 — How do we author the diagrams?&quot;">​</a></h3><p>PRD-008 commits to ≥ 1 visual element per section. Photos cover ~half (NASA / ESA / Wikimedia). The other half are diagrams — Hohmann transfer geometry, conic sections, porkchop colour-bar key, Keplerian elements illustration, free-return trajectory diagram, etc. ~30 needed for V1.</p><table tabindex="0"><thead><tr><th>Option</th><th>Authoring</th><th>Cost / diagram</th><th>Style consistency</th><th>Maintenance</th></tr></thead><tbody><tr><td><strong>A. Hand-drawn Inkscape SVG (committed source)</strong></td><td>Open Inkscape, draw, export, commit <code>.svg</code> to <code>static/diagrams/science/</code></td><td>30–60 min each</td><td>High (single author, single style)</td><td>High — every change is hand-edits</td></tr><tr><td><strong>B. Hand-drawn Figma → SVG export</strong></td><td>Figma file as source of truth; export per diagram</td><td>20–40 min each</td><td>High</td><td>Figma file lives outside repo; harder to PR-review</td></tr><tr><td><strong>C. Hand-coded SVG in JSON</strong></td><td>Each section&#39;s JSON carries inline <code>&lt;svg&gt;</code> markup</td><td>60+ min each</td><td>Variable</td><td>Best for tiny diagrams; awful for anything geometric</td></tr><tr><td><strong>D. Generated via D3 / chart lib at build</strong></td><td>TypeScript build step renders a programmatic SVG</td><td>1–2 hr to author the spec</td><td>Highest (programmatic = perfectly consistent)</td><td>Best — code-review the spec, regenerate any time</td></tr><tr><td><strong>E. AI-generated</strong></td><td>Prompt → image → curate</td><td>5 min each</td><td>Inconsistent; licensing unclear</td><td>Off the table per PA §principles (&quot;attribution is design&quot;)</td></tr></tbody></table><p><strong>Recommendation: A for V1.</strong> Inkscape SVG with the source <code>.svg</code> files committed to the repo. Cheapest to start; we can migrate any single diagram to D (programmatic) if it gets reused or needs to track data. Option E is rejected — we do not generate scientific diagrams via AI.</p><p>The build script <code>scripts/validate-diagrams.ts</code> will fail if any section declares a <code>diagram</code> field with no matching SVG file — same fail-fast contract as the existing data-validation pipeline (ADR-019).</p><hr><h3 id="oq-3-—-chip-ux-on-existing-screens" tabindex="-1">OQ-3 — <code>?</code>-chip UX on existing screens <a class="header-anchor" href="#oq-3-—-chip-ux-on-existing-screens" aria-label="Permalink to &quot;OQ-3 — `?`-chip UX on existing screens&quot;">​</a></h3><p>Every HUD label that names a concept covered in /science gets a <code>?</code> chip. The interaction model has three options:</p><table tabindex="0"><thead><tr><th>Option</th><th>Hover tooltip</th><th>Click action</th></tr></thead><tbody><tr><td><strong>A. Click → navigate to /science</strong></td><td>None</td><td>Full page navigation to <code>/science/[tab]/[section]</code></td></tr><tr><td><strong>B. Hover tooltip + click → navigate</strong></td><td>The section&#39;s intro sentence (≤ 80 chars) on desktop hover</td><td>Same as A</td></tr><tr><td><strong>C. Click → mini-modal popover with the section abstract</strong></td><td>None</td><td>Popover with intro + a &quot;read more&quot; button into /science</td></tr></tbody></table><p><strong>Trade-off.</strong> A is the simplest contract and matches the existing LEARN tab pattern (links, no popovers). B adds desktop polish at zero mobile cost. C is &quot;Wikipedia preview&quot;-style but introduces a new component (the popover) and means every chip click on mobile becomes a context-loss modal — exactly what the PRD wants to avoid.</p><p><strong>Recommendation: B.</strong> The hover tooltip is a desktop-only convenience that doesn&#39;t change the contract on mobile (where there&#39;s no hover). Click-navigates on both. The intro sentence is already in the JSON — surfacing it as a <code>title</code> attribute is one line of code.</p><hr><h3 id="oq-4-—-should-v1-ship-a-glossary-view-alphabetical" tabindex="-1">OQ-4 — Should V1 ship a glossary view (alphabetical)? <a class="header-anchor" href="#oq-4-—-should-v1-ship-a-glossary-view-alphabetical" aria-label="Permalink to &quot;OQ-4 — Should V1 ship a glossary view (alphabetical)?&quot;">​</a></h3><p>PRD-008 V1 is tab-organised reading. A glossary is a flat alphabetical lookup (&quot;show me Vis-viva regardless of which tab it&#39;s under&quot;). Cmd-K covers the search use case; the glossary is for <em>browsing</em>.</p><table tabindex="0"><thead><tr><th>Option</th><th>UX</th><th>Cost</th></tr></thead><tbody><tr><td><strong>A. Tab-only (no glossary)</strong></td><td>Six tabs, each section under one tab</td><td>0 (already in PRD)</td></tr><tr><td><strong>B. Tabs + alphabetical sidebar toggle</strong></td><td>Switch between &quot;by topic&quot; and &quot;A–Z&quot; views</td><td>+2 days</td></tr><tr><td><strong>C. Tabs + a separate <code>/science/all</code> flat list</strong></td><td>URL-addressable glossary mode</td><td>+1 day</td></tr></tbody></table><p><strong>Recommendation: A for V1, defer C to V1.5.</strong> The Cmd-K search lands at the same destination as a glossary entry; we don&#39;t need both in V1. C is clean to add later as a static prerendered route.</p><hr><h3 id="oq-5-—-translation-cadence" tabindex="-1">OQ-5 — Translation cadence <a class="header-anchor" href="#oq-5-—-translation-cadence" aria-label="Permalink to &quot;OQ-5 — Translation cadence&quot;">​</a></h3><p>40 sections × ≤ 200 words ≈ 8 000 source words per locale. With ADR-033&#39;s LLM-only first-pass workflow that&#39;s a half-day batch per locale.</p><p><strong>Question:</strong> does each new locale ship <code>/science</code> simultaneously with the rest of its UI strings, or as a follow-up wave?</p><table tabindex="0"><thead><tr><th>Option</th><th>Risk</th></tr></thead><tbody><tr><td><strong>A. Atomic</strong> — a locale ships only when /science is also done in that locale</td><td>Slows down each locale&#39;s launch by ~half a day</td></tr><tr><td><strong>B. Decoupled</strong> — <code>/science</code> falls back to en-US per ADR-017 until the locale is ready</td><td>Faster launches; readers see English on /science even when the rest of the UI is in their language</td></tr><tr><td><strong>C. Coupled to the LEARN tabs only</strong> — /science ships per locale alongside the mission editorial overlays</td><td>Mid-ground; ties /science to the same translation budget that already exists for missions</td></tr></tbody></table><p><strong>Recommendation: B.</strong> ADR-017&#39;s fallback contract already handles partial-locale state without breaking. A new locale can launch fast; /science follows when the translator is ready.</p><hr><h3 id="oq-6-—-section-atomicity-one-concept-per-url-or-one-tab-per-url" tabindex="-1">OQ-6 — Section atomicity: one concept per URL, or one tab per URL? <a class="header-anchor" href="#oq-6-—-section-atomicity-one-concept-per-url-or-one-tab-per-url" aria-label="Permalink to &quot;OQ-6 — Section atomicity: one concept per URL, or one tab per URL?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>URL examples</th><th>Pros</th></tr></thead><tbody><tr><td><strong>A. One section per URL</strong></td><td><code>/science/orbits/vis-viva</code>, <code>/science/orbits/keplers-laws</code></td><td>Maximum deep-linkability; ?-chip lands precisely</td></tr><tr><td><strong>B. One tab per URL with anchors</strong></td><td><code>/science/orbits#vis-viva</code></td><td>Single page per tab → faster reading flow</td></tr><tr><td><strong>C. Both (A is the canonical URL; tab-page redirects to first section)</strong></td><td><code>/science/orbits/</code> redirects to <code>/science/orbits/vis-viva</code></td><td>Flexibility</td></tr></tbody></table><p><strong>Recommendation: A.</strong> The ?-chip&#39;s whole value is &quot;land the user on the exact concept in one click.&quot; Anchors work but lose the &quot;section is a unit&quot; feeling. The tab page (<code>/science/orbits/</code>) becomes a section-list index — useful as a navigable menu, not a reading surface.</p><hr><h3 id="oq-7-—-diagram-licensing-attribution-chain" tabindex="-1">OQ-7 — Diagram licensing / attribution chain <a class="header-anchor" href="#oq-7-—-diagram-licensing-attribution-chain" aria-label="Permalink to &quot;OQ-7 — Diagram licensing / attribution chain&quot;">​</a></h3><p>Per PA §principles (&quot;attribution is design&quot;), every visual element must have a clear licence + credit. PRD-008 commits to &quot;Public-domain or CC-BY only.&quot;</p><table tabindex="0"><thead><tr><th>Option</th><th>Diagram source rules</th></tr></thead><tbody><tr><td><strong>A. Strict</strong> — only NASA / ESA / Wikimedia public-domain, no third-party CC-BY</td><td>Smallest pool but zero attribution risk</td></tr><tr><td><strong>B. CC-BY allowed with credit</strong> — any CC-BY licence with credit captured per asset</td><td>Wider pool; tracks attribution per file</td></tr><tr><td><strong>C. Original SVGs only</strong></td><td>Lock the visual style; everything attributable to the project</td></tr></tbody></table><p><strong>Recommendation: B for photos, C for geometric diagrams.</strong> Photos: Wikimedia + NASA + CC-BY academic figures, attribution captured in the section&#39;s JSON. Geometric diagrams: original SVGs (per OQ-2 option A) so the visual style of the encyclopedia is the project&#39;s own.</p><hr><h2 id="decision-criteria" tabindex="-1">Decision criteria <a class="header-anchor" href="#decision-criteria" aria-label="Permalink to &quot;Decision criteria&quot;">​</a></h2><p>We accept a recommendation when:</p><ol><li>The bundle-size impact (KaTeX, diagrams, science content JSON) is auditable and &lt; 200 KB initial-load delta.</li><li>The cross-link UX (<code>?</code> chip) does not regress mobile flow on existing screens.</li><li>The build-time validation guarantees every published section has the visual it declares.</li><li>The translation pipeline composes cleanly with ADR-017 / ADR-033 — no new translator workflow.</li><li>The decision is reversible at the per-section level (we can change one diagram or one formula without revisiting the whole framework).</li></ol><hr><h2 id="closure-path" tabindex="-1">Closure path <a class="header-anchor" href="#closure-path" aria-label="Permalink to &quot;Closure path&quot;">​</a></h2><p>This RFC closes with three ADRs:</p><ul><li><strong>ADR-034</strong> — Math rendering: KaTeX server-rendered at build.</li><li><strong>ADR-035</strong> — Diagram authoring pipeline: hand-drawn Inkscape SVG, sources committed to <code>static/diagrams/science/</code>.</li><li><strong>ADR-036</strong> — <code>?</code>-chip cross-screen pattern: click navigates, hover tooltip on desktop, no popover modal.</li></ul><p>Glossary (OQ-4) deferred. Translation cadence (OQ-5) noted in RFC body, no ADR — the en-US fallback is the policy.</p><hr><p><em>Orrery · RFC-011 · v0.1 · Open. Comments welcome on each OQ.</em></p>',58)])])}const m=t(r,[["render",n]]);export{g as __pageData,m as default};
